const http = require("https");

const options = {
  "method": "GET",
  "hostname": "api-test.gateway.equinor.com",
  "port": null,
  "path": "/maintenance-api/maintenance-records?filter=SOME_STRING_VALUE&external-partner-record-id=SOME_STRING_VALUE&created-after-datetime=SOME_STRING_VALUE&plant-id=SOME_STRING_VALUE&changed-since-datetime=SOME_STRING_VALUE&before-datetime=SOME_STRING_VALUE&include-maintenance-record-types=SOME_ARRAY_VALUE&page=SOME_INTEGER_VALUE&per-page=SOME_INTEGER_VALUE",
  "headers": {
    "Authorization": "Bearer REPLACE_BEARER_TOKEN"
  }
};

const req = http.request(options, function (res) {
  const chunks = [];

  res.on("data", function (chunk) {
    chunks.push(chunk);
  });

  res.on("end", function () {
    const body = Buffer.concat(chunks);
    console.log(body.toString());
  });
});

req.end();

